Iteratively attempt to insert each ship into all existing assigns using a cost-aware greedy selection with a deterministic fallback to the first feasible assign including a new one if available, while preserving previous state during evaluation.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for oidx := 0; oidx < orderCount; oidx++ {
		ori := oris[oidx]
		des := dess[oidx]
		shipID := total_ship + oidx

		type candidateInfo struct {
			idx       int
			delta     float64
			newAssign bool
		}
		var bestCandidate candidateInfo
		bestCandidate.delta = 1e18
		bestCandidate.idx = -1

		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestCandidate.delta {
						bestCandidate.delta = delta
						bestCandidate.idx = i
						bestCandidate.newAssign = false
					}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		inserted := false
		if bestCandidate.idx != -1 {
			assign := &dispatch.Assigns[bestCandidate.idx]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					inserted = true
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}

		if !inserted {
			fallbackDone := false
			for tryIdx := 0; tryIdx < dispatch.AssignsLen; tryIdx++ {
				assign := &dispatch.Assigns[tryIdx]
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						fallbackDone = true
						inserted = true
						break
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
			if !fallbackDone && dispatch.AssignsLen < MAXASSIGNS {
				assign := &dispatch.Assigns[dispatch.AssignsLen]
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				assign := &dispatch.Assigns[dispatch.AssignsLen]
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

